cat ~/.openclaw/openclaw.json 2>/dev/null | python3 -c "
import json,sys
d=json.load(sys.stdin)
# Afficher la structure générale
def show(obj, prefix='', depth=0):
    if depth > 3: return
    if isinstance(obj, dict):
        for k,v in obj.items():
            if isinstance(v,(str,int,float,bool)):
                print(f'{prefix}{k}: {v}')
            else:
                print(f'{prefix}{k}:')
                show(v, prefix+'  ', depth+1)
show(d)
" 2>/dev/null | head -80

cat ~/.openclaw/openclaw.json 2>/dev/null | python3 -c "
import json,sys
d=json.load(sys.stdin)
agents = d.get('agents',{})
lst = agents.get('list',{}) or {}
print('=== AGENTS LIST ===')
for name, cfg in lst.items():
    if isinstance(cfg, dict):
        model = cfg.get('model', {})
        if isinstance(model, dict):
            print(f'{name}: primary={model.get(\"primary\",\"N/A\")} fallbacks={model.get(\"fallbacks\",[])}')
        else:
            print(f'{name}: model={model}')
    else:
        print(f'{name}: {cfg}')
print()
print('=== DEFAULT MODEL ===')
defaults = agents.get('defaults',{})
model = defaults.get('model',{})
if isinstance(model, dict):
    print(f'primary={model.get(\"primary\",\"N/A\")}')
    print(f'fallbacks={model.get(\"fallbacks\",[])}')
" 2>/dev/null

