    print(f'Profile: {k}')
    if isinstance(v,dict):
        for kk,vv in v.items():
            if 'token' in kk.lower() or 'key' in kk.lower():
                print(f'  {kk}: ***MASKED***')
            else:
                print(f'  {kk}: {vv}')
